                        array.Add(BillingSubscriptionStatusDetails.DeserializeBillingSubscriptionStatusDetails(item, options));
                    }
                    suspensionReasonDetails = array;
                    continue;
                }
                if (options.Format != "W")
                {
                    additionalBinaryDataProperties.Add(prop.Name, BinaryData.FromString(prop.Value.GetRawText()));
                }
            }
            return new BillingSubscriptionProperties(
                autoRenew,
                subscriptionBeneficiaryTenantId,
                beneficiary,
                billingFrequency,
                billingProfileId,
                billingPolicies ?? new ChangeTrackingDictionary<string, string>(),
                billingProfileDisplayName,
                billingProfileName,
                consumptionCostCenter,
                subscriptionCustomerId,
                customerDisplayName,
                customerName,
                displayName,
                enrollmentAccountId,
                enrollmentAccountDisplayName,
                enrollmentAccountSubscriptionDetails,
                invoiceSectionId,
                invoiceSectionDisplayName,
                invoiceSectionName,
                lastMonthCharges,
                monthToDateCharges,
                nextBillingCycleDetails,
                offerId,
                productCategory,
                productType,
                productTypeId,
                purchaseOn,
                quantity,
                reseller,
                renewalTermDetails,
                skuId,
                skuDescription,
                systemOverrides,
                resourceUri,
                termDuration,
                termStartOn,
                termEndOn,
                provisioningTenantId,
                status,
                operationStatus,
                provisioningState,
                subscriptionId,
                suspensionReasons ?? new ChangeTrackingList<string>(),
                suspensionReasonDetails ?? new ChangeTrackingList<BillingSubscriptionStatusDetails>(),
                additionalBinaryDataProperties);
        }
    }
}
